def check_opens_webshops(paths, code):
    # The plan must open all four webshops before searching for the product.
    required_webshops = [
        "http://localhost:8081",
        "http://localhost:8082",
        "http://localhost:8083",
        "http://localhost:8084"
    ]
    opened_webshops = set()

    for path in paths:
        for action in path:
            if action.func == "open_page" and action.args[0] in required_webshops:
                opened_webshops.add(action.args[0])

    if opened_webshops == set(required_webshops):
        return PropertyResult(
            name="T1: All webshops are opened",
            passed=True,
            message="All required webshops have been opened."
        )

    missing_webshops = required_webshops - opened_webshops
    return PropertyResult(
        name="T1: All webshops are opened",
        passed=False,
        message=f"The following webshops were not opened: {', '.join(missing_webshops)}."
    )


def check_searches_for_product(paths, code):
    # The plan must search for the product "AMD Ryzen 9 5900X" in each opened webshop.
    search_text = "AMD Ryzen 9 5900X"
    search_count = 0

    for path in paths:
        for action in path:
            if action.func == "search_on_page" and action.args[1] == search_text:
                search_count += 1

    if search_count >= 4:
        return PropertyResult(
            name="T2: Searches for the product in all webshops",
            passed=True,
            message="The product has been searched for in all webshops."
        )

    return PropertyResult(
        name="T2: Searches for the product in all webshops",
        passed=False,
        message="The product was not searched for in all webshops."
    )


def check_extracts_information(paths, code):
    # After searching for the product, the plan must extract information from the pages.
    extraction_needed = False

    for path in paths:
        for action in path:
            if action.func == "search_on_page":
                extraction_needed = True
            if extraction_needed and action.func == "extract_information_from_page":
                return PropertyResult(
                    name="T3: Extracts information after searching",
                    passed=True,
                    message="Information is extracted after searching for the product."
                )

    return PropertyResult(
        name="T3: Extracts information after searching",
        passed=False,
        message="No information extraction found after searching for the product."
    )


def check_fills_final_result(paths, code):
    # The plan must fill the final result into the text field on the solution page.
    final_result_filled = False

    for path in paths:
        for action in path:
            if action.func == "fill_text_field" and action.args[0] == "Type your final answer here...":
                final_result_filled = True
                break

    if final_result_filled:
        return PropertyResult(
            name="T4: Fills final result into the text field",
            passed=True,
            message="Final result is filled into the text field."
        )

    return PropertyResult(
        name="T4: Fills final result into the text field",
        passed=False,
        message="Final result was not filled into the text field."
    )


def check_submits_final_result(paths, code):
    # The plan must press the "Submit Final Result" button after filling the result.
    submit_pressed = False

    for path in paths:
        for action in path:
            if action.func == "press_button" and action.args[0] == "Submit Final Result":
                submit_pressed = True
                break

    if submit_pressed:
        return PropertyResult(
            name="T5: Submits final result",
            passed=True,
            message="Final result is submitted."
        )

    return PropertyResult(
        name="T5: Submits final result",
        passed=False,
        message="Final result was not submitted."
    )

