    if "open_page('http://localhost:8085')" in code:
        return PropertyResult(name='T1: Plan navigates to the solution page', passed=True, message='Plan includes navigation to the solution page.')
    return PropertyResult(name='T1: Plan navigates to the solution page', passed=False, message='No navigation to the solution page found.')

def check_fills_text_field(paths, code):
    if 'fill_text_field(' in code:
        return PropertyResult(name='T2: Plan fills the text field with results', passed=True, message='Plan includes filling the text field with results.')
    return PropertyResult(name='T2: Plan fills the text field with results', passed=False, message='No fill_text_field call found for entering results.')

def check_submits_final_result(paths, code):
    if "press_button('Submit Final Result')" in code:
        return PropertyResult(name='T3: Plan submits the final result', passed=True, message='Plan includes pressing the submit button for final results.')
    return PropertyResult(name='T3: Plan submits the final result', passed=False, message='No press_button call found for submitting final results.')

def check_searches_for_product(paths, code):
    if 'search(' in code and 'Samsung Galaxy S24 Plus' in code:
        return PropertyResult(name='T4: Plan searches for the product', passed=True, message='Plan includes a search for the Samsung Galaxy S24 Plus.')
    return PropertyResult(name='T4: Plan searches for the product', passed=False, message='No search for the Samsung Galaxy S24 Plus found.')
